import collections

def min_vertices_to_reach_all_nodes(n: int, edges: list[tuple[int, int]]) -> int:
    if n == 0:
        return 0

    graph = collections.defaultdict(list)
    rev_graph = collections.defaultdict(list)

    for u, v in edges:
        graph[u].append(v)
        rev_graph[v].append(u)

    visited = [False] * n
    order_stack = []

    def dfs1(u):
        visited[u] = True
        for v in graph[u]:
            if not visited[v]:
                dfs1(v)
        order_stack.append(u)

    for i in range(n):
        if not visited[i]:
            dfs1(i)

    visited = [False] * n
    scc_map = [-1] * n

    def dfs2(u, current_scc_id):
        visited[u] = True
        scc_map[u] = current_scc_id
        for v in rev_graph[u]:
            if not visited[v]:
                dfs2(v, current_scc_id)

    scc_count = 0
    while order_stack:
        u = order_stack.pop()
        if not visited[u]:
            dfs2(u, scc_count)
            scc_count += 1

    if scc_count == 0:
        return 0
    if scc_count == 1:
        return 1

    in_degree_condensation = [0] * scc_count

    for u, v_list in graph.items():
        for v in v_list:
            if scc_map[u] != scc_map[v]:
                in_degree_condensation[scc_map[v]] += 1

    source_sccs = 0
    for i in range(scc_count):
        if in_degree_condensation[i] == 0:
            source_sccs += 1

    return source_sccs
